mapper.select:
SELECT sis.*, su.id as su_id, su.name as su_name, su.student_user_id as su_student_id, su.gender as su_gender, su.grade as su_grade, su.major_id as su_major_id, su.class_id as su_class_id, c.id as c_id, c.company_name as c_company_name, c.contact_person as c_contact_person, c.contact_phone as c_contact_phone, c.contact_email as c_contact_email, c.address as c_address, p.id as p_id, p.position_name as p_position_name, p.requirements as p_requirements, p.planned_recruit as p_planned_recruit, p.recruited_count as p_recruited_count, p.remaining_quota as p_remaining_quota FROM student_internship_status sis LEFT JOIN student_users su ON sis.student_id = su.id LEFT JOIN company_users c ON sis.company_id = c.id LEFT JOIN position p ON sis.position_id = p.id
AND su.id = #{studentId}
AND su.name LIKE CONCAT('%', #{name}, '%')
AND su.gender = #{gender}
AND sis.status = #{status}
AND sis.company_id = #{companyId}
AND c.company_name LIKE CONCAT('%', #{companyName}, '%')
ORDER BY sis.create_time DESC

SELECT COUNT(*) FROM student_internship_status sis
INNER JOIN student_users su ON sis.student_id = su.id
WHERE su.major_id = #{majorId} AND sis.status = #{status}

SELECT su.student_user_id AS studentUserId, su.name AS studentName, m.name AS majorName, c.name AS className, CASE sis.status WHEN 0 THEN '未找到实习' WHEN 1 THEN '有Offer未确定' WHEN 2 THEN '已确定实习' WHEN 3 THEN '实习结束' ELSE '未知' END AS statusText, co.company_name AS companyName, p.position_name AS positionName, sis.update_time AS updatedTime FROM student_users su LEFT JOIN student_internship_status sis ON su.id = sis.student_id LEFT JOIN major m ON su.major_id = m.id LEFT JOIN class c ON su.class_id = c.id LEFT JOIN company_users co ON sis.company_id = co.id LEFT JOIN position p ON sis.position_id = p.id
sis.status = #{status}
ORDER BY m.name, c.name, su.student_user_id

SELECT sis.*, su.id as su_id, su.name as su_name, su.student_user_id as su_student_id, su.gender as su_gender, su.grade as su_grade, su.major_id as su_major_id, su.class_id as su_class_id, c.id as c_id, c.company_name as c_company_name, c.contact_person as c_contact_person, c.contact_phone as c_contact_phone, c.contact_email as c_contact_email, c.address as c_address, p.id as p_id, p.position_name as p_position_name, p.requirements as p_requirements, p.planned_recruit as p_planned_recruit, p.recruited_count as p_recruited_count, p.remaining_quota as p_remaining_quota FROM student_internship_status sis LEFT JOIN student_users su ON sis.student_id = su.id LEFT JOIN company_users c ON sis.company_id = c.id LEFT JOIN position p ON sis.position_id = p.id WHERE sis.recall_status = 1
AND su.id = #{studentId}
AND su.name LIKE CONCAT('%', #{name}, '%')
AND su.gender = #{gender}
AND sis.company_id = #{companyId}
AND c.company_name LIKE CONCAT('%', #{companyName}, '%')
ORDER BY sis.recall_apply_time DESC
